module RefModule(
    input signed [15:0] in1,
    input signed [15:0] in2,
    input clk,
    output signed [16:0] out
);reg signed [16:0] sum;

always @(posedge clk) begin
    sum <= in1 + in2;
end

wire __cond7_tmp = sum[16];
assign out = __cond7_tmp ? {1'b1, sum[15:0]} : sum[15:0];

endmodule
